-- Enrichment marathon batch: Label Studio, Labelbox, Lago, Lancache, LanceDB, Langflow, Langfuse, LangSmith

-- ── Label Studio ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Label Studio is an open-source, multi-modal data labeling and annotation platform for computer vision, NLP, audio, and LLM evaluation, built by HumanSignal.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (Community Edition, self-hosted); Starter Cloud from $99/user/month$q$, starting_price),
  founded_year = COALESCE(2019, founded_year),
  company_size = COALESCE($q$51-200 employees$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Label Studio Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Label Studio is the leading open-source data labeling tool for AI and ML. See 2026 pricing, key features, HumanSignal Enterprise details, and top alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Label Studio is an open-source, multi-type data annotation and labeling platform used to prepare training data for machine learning models and to evaluate the outputs of AI systems, including large language models. The project was originally built under the name Heartex, founded in 2019 by Michael Malyuk and Max Tkachenko, and the company rebranded to HumanSignal in June 2023 to reflect its broader focus on tools for data science and AI teams working with foundation models. HumanSignal is headquartered in San Francisco, California, employs roughly 50 to 200 people distributed across several continents, and raised a $25 million Series A round in May 2022 led by Redpoint Ventures with participation from Unusual Ventures, Bow Capital, and Swift Ventures, bringing its total disclosed funding to about $30 million. Label Studio itself is described as the most widely used open-source data labeling tool, with more than one million AI practitioners reportedly using it and organizations such as Cloudflare, NVIDIA, Meta, IBM, and Intel cited among its users. Architecturally, Label Studio is a self-hostable web application with a configurable, XML-like labeling interface that administrators can adapt to nearly any annotation task without writing custom frontend code, plus an API, Python SDK, and webhook system that let engineering teams wire labeling directly into machine learning pipelines, connect external cloud storage as data sources, and plug in machine learning models to pre-label or actively assist annotators. The platform supports a wide range of data modalities within one tool, including computer vision tasks like image classification, object detection, and semantic segmentation; natural language processing tasks such as named entity recognition, sentiment analysis, and PDF or OCR-based document labeling; audio and speech tasks including transcription, speaker diarization, and emotion recognition; time-series data from IoT and sensor streams; and multi-modal projects that combine several of these data types in a single labeling interface. As LLM development has grown, Label Studio has added specialized tooling for reinforcement learning from human feedback (RLHF), fine-tuning dataset collection, and building custom evaluation benchmarks and rubrics, including LLM-as-a-judge workflows available on the Enterprise tier. Commercially, the product follows a freemium structure with four effective tiers. The Community Edition is entirely free, open source, and self-hosted, giving technical teams full access to the core labeling engine, configurable interfaces, and API without licensing cost. Starter Cloud is a fully hosted plan priced at $99 per user per month for up to 12 users, offering a managed multi-modal labeling platform with role-based access control, quality workflows, automated task distribution, and a support portal, and it is available with a free trial. The Enterprise tier is custom-priced and adds everything in Starter plus single sign-on via SAML or LDAP, programmable and embeddable labeling interfaces, enhanced quality analytics, LLM-as-a-judge and bulk auto-labeling, SOC2 and HIPAA compliance for both cloud and on-premises deployments, the highest-priority SLAs, and a dedicated customer success manager. A separate Data Services offering provides project-based, custom-quoted human labeling services delivered through purpose-built facilities and domain experts, aimed at organizations that need outsourced annotation capacity rather than just software. Label Studio's core audience spans individual ML engineers and researchers who need a free, flexible labeling tool they can self-host, up through regulated enterprises and AI labs that need compliant, large-scale human-in-the-loop workflows for both traditional ML training data and modern LLM evaluation. Its most direct competitors include Labelbox, Scale AI, SuperAnnotate, Encord, V7 (Darwin), Kili Technology, Amazon SageMaker Ground Truth, and the open-source tool CVAT; Label Studio differentiates itself primarily through being genuinely open source at its core (unlike most rivals, which are closed-source SaaS products from the outset), its unusually broad support for many data modalities within a single unified interface rather than separate tools per data type, and its growing specialization in evaluating generative AI and LLM outputs alongside traditional annotation work.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'b86f2d2c-9242-4ac1-8381-48bac80db6dd';

