-- ── Lago ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Lago is an open-source, usage-based billing and metering platform that helps SaaS companies manage subscriptions, invoicing, and revenue operations.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free (self-hosted Community Edition); Cloud plans are custom-quoted$q$, starting_price),
  founded_year = COALESCE(2021, founded_year),
  company_size = COALESCE($q$51-100 employees$q$, company_size),
  headquarters = COALESCE($q$Paris, France$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$French$q$]::text[],
  seo_title = COALESCE($q$Lago Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Lago is an open-source usage-based billing platform for SaaS. See 2026 pricing, self-hosted vs cloud features, pros and cons, and top billing alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Lago is an open-source metering and usage-based billing platform designed to give software companies, particularly API and infrastructure-heavy SaaS businesses, a self-controlled alternative to closed billing systems like Stripe Billing or Zuora. The company was founded in 2021 in Paris, France, by Anh-Tho Chuong and Raffi Sarkissian, who previously worked together at the French fintech unicorn Qonto and identified recurring bottlenecks in how growing companies handled complex, usage-based pricing. Lago went through Y Combinator's Summer 2021 batch and has since raised a total of roughly $22.1 million, including a $7 million seed round led by SignalFire and a $15 million Series A round led by FirstMark Capital announced in March 2024; other backers include Y Combinator itself and a number of notable individual investors such as former Stripe and OpenAI developer relations lead Romain Huet, Hugging Face CEO Clement Delangue, and MongoDB's head of monetization Meghan Gill. The company is expanding its presence in the United States while remaining headquartered in Paris. Architecturally, Lago is built as a real-time metering and billing engine capable of ingesting high volumes of usage events, reportedly up to around 15,000 events per second, and converting that raw usage data into billable metrics, invoices, and revenue analytics. The product supports usage-based, flat subscription, hybrid, and prepaid credit-based pricing models on the same customer plan, along with wallets, prepaid credit balances, and progressive billing primitives that let companies bill customers as usage accrues rather than only at the end of a billing cycle. Every customer, subscription, and billing event is exposed through both a webhook system and a GraphQL and REST API, and the platform plugs into external payment processors such as Stripe, GoCardless, and Adyen, as well as tax engines, rather than trying to replace payment processing itself. A background job queue built on Sidekiq handles retry logic for high-volume usage ingestion, which is important for infrastructure and API businesses billing on metrics like API calls, compute time, or data processed. The core Lago platform, referred to as the Community Edition, is released under the AGPLv3 license and is genuinely free to self-host indefinitely via Docker on a company's own infrastructure, with no license fee, time limit, or feature-crippled trial; it includes the full billing engine, metering, invoicing, entitlements and plan customization, wallets, analytics dashboards, multiple billing entities, and role-based API key permissions. Lago's commercial offering, Lago Cloud, is a managed hosting option sold in two quote-only tiers, Business and Enterprise, that layer on capabilities not included in the free self-hosted core, such as the customer-facing billing portal, credit notes and refunds, automatic dunning for failed payments, tax integrations, CRM and accounting software integrations, AI billing agents, and an embeddable billing UI component called Lago Embedded; pricing for both cloud tiers is not published and requires contacting Lago's sales team or booking a demo. Lago's target customers are engineering-led SaaS and API companies, especially those with usage-based or consumption-based pricing models such as AI platforms billing on tokens or compute, infrastructure providers billing on API calls or storage, and other developer-facing products where flat per-seat billing does not fit the business model; the company frequently positions itself as particularly well suited to teams that want the transparency and portability of an open-source, self-hostable billing core without being locked into a single vendor's proprietary system. Its main competitors include Stripe Billing, Chargebee, Zuora, Recurly, and, most directly among usage-based billing specialists, Metronome and Orb; Lago differentiates itself from all of these primarily through its open-source, self-hostable AGPLv3 core, a value proposition none of those closed-source competitors offer, giving engineering teams the ability to inspect, modify, and run the billing engine entirely within their own infrastructure while still having the option to move to a managed cloud plan as they scale.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'cd422245-3239-421a-87c7-ef20ba5506e5';

