-- ── Lancache ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Lancache (LanCache.NET) is a free, open-source LAN caching proxy that speeds up and reduces bandwidth for game downloads and updates from Steam, Epic, and other platforms.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Lancache Review 2026: Features, Setup and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Lancache is a free, open-source LAN caching server for Steam, Epic, and other game downloads. See how it works, setup basics, pros and cons, and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Lancache, published as LanCache.NET, is a free and open-source caching proxy server designed to speed up game downloads and updates for multiple users sharing the same local area network, most commonly at LAN parties, gaming events, esports venues, internet cafes, and multi-device households. Rather than every device on a network independently downloading the same multi-gigabyte game install or patch from the internet, Lancache intercepts these download requests, caches the content locally the first time it is requested, and serves subsequent requests for the same files directly from the local network, dramatically reducing internet bandwidth usage and speeding up download times for everyone on the network. The project's technical lineage traces back to work originally done by Multiplay, a UK esports and gaming infrastructure company, whose engineer Bruno Gysels is credited with early lancache implementations; the earliest known public documentation of the underlying dynamic game-install caching technique, using Nginx as a caching layer, appeared in an April 2014 blog post authored under the name Dilbert at MPUK. Multiplay's original lancache project is no longer under active development, but the concept was subsequently forked, generalized, and maintained forward by the community-driven LanCache.NET project, which today lives under the lancachenet organization on GitHub and is described on its own site as a UKLans community project. The entire codebase is released under the MIT License, making it fully open source and free to modify, redistribute, and self-host with no licensing fee. Because it is a community-maintained open-source utility rather than a venture-backed company, Lancache has no headquarters, founding date, employee count, or funding history in the traditional sense; its development and support are coordinated publicly through GitHub repositories, issue trackers, and community discussion channels rather than a formal corporate structure. Technically, a Lancache deployment consists of a caching proxy component, most commonly distributed as a set of Docker containers, paired with a DNS server that redirects traffic for supported gaming platforms toward the local cache instead of the public internet. This DNS-based interception is the preferred and most reliable method of directing traffic to the cache, since it works transparently for any device on the network without requiring per-device proxy configuration. The project maintains cache rules for a wide range of major content distributors, including Steam, the Epic Games Launcher and Fortnite, Battle.net, Origin, Windows Update, Riot Games, Sony, Microsoft Xbox, GOG, ArenaNet's Guild Wars titles, Wargaming, and Uplay, among others, with new rules added over time as distributors change their infrastructure. A significant technical limitation is that Lancache can only cache traffic served over plain HTTP, since HTTPS-encrypted traffic cannot be transparently inspected and cached by a standard proxy; the project addresses part of this limitation with an SNI proxy component that can route HTTPS connections to the correct backend without decrypting them, though this only helps with routing, not with actual content caching, since encrypted payloads cannot be stored and reused. Lancache has no pricing structure at all, since it is entirely free open-source software with no paid tiers, subscriptions, or commercial edition; the only cost to a user is whatever server hardware, storage, and network infrastructure they choose to run the caching proxy on. Its primary audience is LAN party organizers, gaming event and tournament operators, internet cafes, university dormitories, military installations, and hobbyist home-lab users who want to avoid redundant multi-user downloads of the same large game files over a shared or limited internet connection. Because it occupies a narrow, purpose-built niche, Lancache does not have direct commercial competitors in the way that SaaS products do; the closest points of comparison are its own technical predecessor, the original Multiplay lancache project and the earlier community concept sometimes referred to as SteamCache, as well as generic enterprise CDN caching appliances that are far more expensive and not purpose-built for consumer game distribution platforms. Lancache's continued relevance depends on active community maintenance to keep pace with content distributors changing their CDN domains and download infrastructure, which can break existing cache rules and requires ongoing updates from contributors to keep the project functional for platforms like Steam, Epic Games, and Battle.net.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'b2362d6f-46ea-441d-ab8b-269f62578937';

