INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c392b66f-4dcb-40e6-989c-f072b529aff7', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ebd27bea-946b-435d-8767-2c6ce3d3d696', $q$Nested trace observability$q$, $q$Every LLM call, tool invocation, and agent step is captured as a replayable trace with latency and token-cost data.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ebd27bea-946b-435d-8767-2c6ce3d3d696', $q$Dataset-driven evaluation$q$, $q$Build test datasets and run offline or online evaluations using LLM-as-a-judge, custom code, or human review.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ebd27bea-946b-435d-8767-2c6ce3d3d696', $q$Prompt Hub and Playground$q$, $q$Version-controlled prompts can be referenced by name in code and updated without redeploying the application.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ebd27bea-946b-435d-8767-2c6ce3d3d696', $q$Managed agent deployment$q$, $q$Deploy agents as Agent Server endpoints with automatic scaling, uptime, and monitoring built in.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ebd27bea-946b-435d-8767-2c6ce3d3d696', $q$Automated pattern and failure detection$q$, $q$Trace data is automatically clustered to surface usage patterns, common behaviors, and failure modes.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ebd27bea-946b-435d-8767-2c6ce3d3d696', $q$Dashboards and alerting$q$, $q$Track cost, latency, error rates, and quality metrics from online evals through configurable dashboards and alerts.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ebd27bea-946b-435d-8767-2c6ce3d3d696', $q$Framework-agnostic integration$q$, $q$Works with applications built on LangChain, LangGraph, or entirely custom LLM application code.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ebd27bea-946b-435d-8767-2c6ce3d3d696', $q$Self-hosted and hybrid deployment$q$, $q$Enterprise customers can run LangSmith in self-hosted or hybrid environments for data residency and compliance needs.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ebd27bea-946b-435d-8767-2c6ce3d3d696', $q$Combines tracing, evaluation, prompt management, and agent deployment in a single platform$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ebd27bea-946b-435d-8767-2c6ce3d3d696', $q$Framework-agnostic, so it is useful even for teams not using the LangChain framework$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ebd27bea-946b-435d-8767-2c6ce3d3d696', $q$Free Developer tier and moderately priced Plus tier make it accessible for individuals and small teams$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ebd27bea-946b-435d-8767-2c6ce3d3d696', $q$Backed by LangChain's substantial funding and rapid engineering headcount growth$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ebd27bea-946b-435d-8767-2c6ce3d3d696', $q$Used by well-known enterprise customers, indicating production-grade reliability$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ebd27bea-946b-435d-8767-2c6ce3d3d696', $q$Free Developer plan is capped at a single seat and 5,000 traces per month$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ebd27bea-946b-435d-8767-2c6ce3d3d696', $q$Usage-based LCU and LSU charges can make costs harder to predict for high-volume agent workloads$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ebd27bea-946b-435d-8767-2c6ce3d3d696', $q$Enterprise pricing is custom and not published, requiring a sales conversation$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ebd27bea-946b-435d-8767-2c6ce3d3d696', $q$Deep feature set has a learning curve compared to narrower, single-purpose observability tools$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ebd27bea-946b-435d-8767-2c6ce3d3d696', $q$Closely tied to the LangChain ecosystem's roadmap and terminology, which may feel unfamiliar to non-LangChain teams$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ebd27bea-946b-435d-8767-2c6ce3d3d696', $q$Is LangSmith free to use?$q$, $q$Yes, LangSmith offers a free Developer plan for a single user with up to 5,000 traces per month. Paid Plus and Enterprise plans add more traces, seats, and enterprise features.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ebd27bea-946b-435d-8767-2c6ce3d3d696', $q$Who built LangSmith?$q$, $q$LangSmith is built by LangChain, founded in early 2023 by Harrison Chase and Ankush Gola, and launched in beta in summer 2023.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ebd27bea-946b-435d-8767-2c6ce3d3d696', $q$Does LangSmith require using the LangChain framework?$q$, $q$No, LangSmith is framework-agnostic and works with applications built on LangChain, LangGraph, or entirely custom code.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ebd27bea-946b-435d-8767-2c6ce3d3d696', $q$How much does LangSmith cost?$q$, $q$LangSmith's Plus plan costs $39 per seat per month with 10,000 traces included, while Enterprise uses custom annual pricing; usage beyond plan limits is billed via LangChain Compute Units ($1.50 each) and Storage Units ($1.00 each).$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ebd27bea-946b-435d-8767-2c6ce3d3d696', $q$Can LangSmith deploy AI agents, not just monitor them?$q$, $q$Yes, LangSmith's Deployment module lets teams host agents as managed Agent Server endpoints with automatic scaling, uptime, and monitoring.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ebd27bea-946b-435d-8767-2c6ce3d3d696', $q$What are the main alternatives to LangSmith?$q$, $q$Common alternatives include Langfuse, Helicone, Arize Phoenix, Weights and Biases Weave, and Braintrust.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ebd27bea-946b-435d-8767-2c6ce3d3d696', $q$AI agent debugging and tracing$q$, $q$Engineering teams inspect nested traces of every LLM call and tool invocation to debug and understand agent behavior.$q$, $q$AI and backend engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ebd27bea-946b-435d-8767-2c6ce3d3d696', $q$LLM application evaluation and regression testing$q$, $q$Teams build evaluation datasets and run experiments to compare prompt or model versions before shipping changes to production.$q$, $q$AI product and evaluation teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ebd27bea-946b-435d-8767-2c6ce3d3d696', $q$Managed agent hosting$q$, $q$Organizations deploy AI agents as scalable, monitored endpoints using LangSmith's Agent Server deployment feature.$q$, $q$Enterprise platform engineering teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ebd27bea-946b-435d-8767-2c6ce3d3d696', $q$Developer$q$, $q$$0/seat/month$q$, $q$Free, pay-as-you-go after free tier$q$, NULL, $q$["Up to 5,000 traces/month","Maximum 1 seat","Community forum support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ebd27bea-946b-435d-8767-2c6ce3d3d696', $q$Plus$q$, $q$$39/seat/month$q$, $q$Monthly, self-serve$q$, NULL, $q$["Up to 10,000 traces/month","Unlimited additional seats at $39 each","Email support","1 free small serverless deployment"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ebd27bea-946b-435d-8767-2c6ce3d3d696', $q$Enterprise$q$, $q$Custom pricing$q$, $q$Annual invoice$q$, NULL, $q$["Custom trace allocation","SLA guarantees","Dedicated engineers and team training","Self-hosted and hybrid deployment options"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ebd27bea-946b-435d-8767-2c6ce3d3d696', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$LangSmith is LangChain's agent engineering platform for tracing, evaluating, debugging, and deploying LLM applications and AI agents, used across both development and production environments.$q$, $q$Founded by Harrison Chase and Ankush Gola in early 2023 and launched in beta that summer, LangSmith has grown from a LangChain-specific debugging tool into a framework-agnostic platform that also works with applications not built on LangChain.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ebd27bea-946b-435d-8767-2c6ce3d3d696', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$LangSmith's tracing engine captures every LLM call, tool invocation, and agent step as a nested, replayable trace with latency and token-cost data, feeding a dataset-driven evaluation system that supports LLM-as-a-judge, custom code, and human review.$q$, $q$A Prompt Hub and Playground turn prompts into version-controlled assets, while the Deployment module lets teams host agents as managed Agent Server endpoints with automatic scaling, uptime, and monitoring.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ebd27bea-946b-435d-8767-2c6ce3d3d696', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$LangSmith offers a free Developer plan with up to 5,000 traces per month for a single user, a $39/seat/month Plus plan with 10,000 traces included and unlimited additional seats, and a custom-priced Enterprise plan with SLAs and self-hosted or hybrid deployment options.$q$, $q$Usage beyond a plan's trace allowance is billed via LangChain Compute Units at $1.50 each and LangChain Storage Units at $1.00 each, covering agent compute and data storage respectively.$q$]::text[], 2);
